pub fn authorize_work_intent_update_status(
    requested: WorkIntentStatus,
    is_expired: bool,
) -> Result<WorkIntentStatus, MobCoordinationLifecycleAuthorityError> {
    match requested {
        WorkIntentStatus::Planned if !is_expired => Ok(WorkIntentStatus::Planned),
        WorkIntentStatus::Active if !is_expired => Ok(WorkIntentStatus::Active),
        WorkIntentStatus::Blocked if !is_expired => Ok(WorkIntentStatus::Blocked),
        WorkIntentStatus::Completed => Ok(WorkIntentStatus::Completed),
        WorkIntentStatus::Cancelled => Ok(WorkIntentStatus::Cancelled),
        other => Err(
            MobCoordinationLifecycleAuthorityError::WorkIntentStatusRejected {
                requested: other,
                is_expired,
            },
        ),
    }
}

pub fn authorize_resource_claim_update_status(
    requested: ResourceClaimStatus,
    is_expired: bool,
) -> Result<ResourceClaimStatus, MobCoordinationLifecycleAuthorityError> {
    match requested {
        ResourceClaimStatus::Active if !is_expired => Ok(ResourceClaimStatus::Active),
        ResourceClaimStatus::Released => Ok(ResourceClaimStatus::Released),
        ResourceClaimStatus::Expired => Ok(ResourceClaimStatus::Expired),
        ResourceClaimStatus::Cancelled => Ok(ResourceClaimStatus::Cancelled),
        other => Err(
            MobCoordinationLifecycleAuthorityError::ResourceClaimStatusRejected {
                requested: other,
                is_expired,
            },
        ),
    }
}

#[must_use]
pub fn work_intent_status_is_terminal(status: WorkIntentStatus) -> bool {
    match status {
        WorkIntentStatus::Planned => false,
        WorkIntentStatus::Active => false,
        WorkIntentStatus::Blocked => false,
        WorkIntentStatus::Completed => true,
        WorkIntentStatus::Cancelled => true,
    }
}

#[must_use]
pub fn resource_claim_status_is_terminal(status: ResourceClaimStatus) -> bool {
    match status {
        ResourceClaimStatus::Active => false,
        ResourceClaimStatus::Released => true,
        ResourceClaimStatus::Expired => true,
        ResourceClaimStatus::Cancelled => true,
    }
}

#[must_use]
pub fn resource_claim_status_is_expired(status: ResourceClaimStatus) -> bool {
    matches!(status, ResourceClaimStatus::Expired)
}
